let is_transition = next.is_valid - next.is_first;
let is_last = local.is_valid - is_transition.clone();

// Air index decrements by 1
builder
    .when(is_transition.clone())
    .assert_eq(next.air_idx, local.air_idx - AB::Expr::ONE);
// Air index ends at 0
builder.when(is_last.clone()).assert_zero(local.air_idx);

// Initialize running sums
assert_array_eq(
    &mut builder.when(local.is_first),
    local.cur_p_sum,
    local.sum_claim_p,
);
assert_array_eq(
    &mut builder.when(local.is_first),
    local.cur_q_sum,
    local.sum_claim_q,
);

// Add air sums to running sums
assert_array_eq(
    &mut builder.when(is_transition.clone()),
    next.cur_p_sum,
    ext_field_add(local.cur_p_sum, next.sum_claim_p),
);
assert_array_eq(
    &mut builder.when(is_transition.clone()),
    next.cur_q_sum,
    ext_field_add(local.cur_q_sum, next.sum_claim_q),
);

// Initialize hash
// h = p + mu * q
assert_array_eq(
    &mut builder.when(local.is_first),
    local.cur_hash,
    ext_field_add(
        local.sum_claim_p,
        ext_field_multiply(local.mu, local.sum_claim_q),
    ),
);

// Update hash
// h' = p + mu * (q + mu * h)
assert_array_eq(
    &mut builder.when(is_transition.clone()),
    next.cur_hash,
    ext_field_add(
        next.sum_claim_p,
        ext_field_multiply(
            next.mu,
            ext_field_add(
                next.sum_claim_q,
                ext_field_multiply(next.mu, local.cur_hash),
            ),
        ),
    ),
);

// Air index starts at num_present_airs - 1
self.fraction_folder_input_bus.receive(
    builder,
    local.proof_idx,
    FractionFolderInputMessage {
        num_present_airs: local.air_idx + AB::Expr::ONE,
    },
    local.is_first,
);

// Sample mu
self.transcript_bus.sample_ext(
    builder,
    local.proof_idx,
    local.tidx + AB::Expr::from_usize(2 * D_EF),
    local.mu,
    local.is_first,
);
self.transcript_bus.observe_ext(
    builder,
    local.proof_idx,
    local.tidx + AB::Expr::from_usize(D_EF),
    local.sum_claim_q,
    local.is_valid,
);
self.transcript_bus.observe_ext(
    builder,
    local.proof_idx,
    local.tidx,
    local.sum_claim_p,
    local.is_valid,
);

self.sumcheck_bus.send(
    builder,
    local.proof_idx,
    SumcheckClaimMessage {
        round: AB::Expr::NEG_ONE,
        value: local.cur_hash.map(Into::into),
    },
    is_last.clone(),
);

// Receive initial tidx and input layer claim from gkr module
self.gkr_claim_bus.receive(
    builder,
    local.proof_idx,
    BatchConstraintModuleMessage {
        // Skip lambda
        tidx: local.tidx,
        gkr_input_layer_claim: [local.cur_p_sum, local.cur_q_sum],
    },
    is_last,
);
// Send final tidx value to univariate sumcheck
self.univariate_sumcheck_input_bus.send(
    builder,
    local.proof_idx,
    UnivariateSumcheckInputMessage {
        // Skip mu
        tidx: local.tidx + AB::Expr::from_usize(3 * D_EF),
    },
    local.is_first,
);

self.mu_bus.add_key_with_lookups(
    builder,
    local.proof_idx,
    BatchConstraintConductorMessage {
        msg_type: BatchConstraintInnerMessageType::Mu.to_field(),
        idx: AB::Expr::ZERO,
        value: local.mu.map(Into::into),
    },
    local.is_first,
);

#[derive(AlignedBorrow, Copy, Clone)]
#[repr(C)]
pub struct InteractionsFoldingCols<T> {
    pub is_valid: T,
    pub is_first: T,
    pub proof_idx: T,

    pub beta_tidx: T,

    pub air_idx: T,
    pub sort_idx: T,
    pub interaction_idx: T,

    pub has_interactions: T,

    pub is_first_in_air: T,
    /// It's true for the num row, which doesn't need to be beta folded.
    pub is_first_in_message: T, // aka "is_mult"
    // the second in message is the first denom, and it's cur_sum is the folded denom
    pub is_second_in_message: T,
    pub is_bus_index: T,

    pub idx_in_message: T,
    pub value: [T; D_EF],
    /// Current sum for doing beta folding. This is the value for one interaction.
    /// When local.is_first_in_message, next.cur_sum should be the folded denom.
    /// (because local row is for the num row, which doesn't need to be beta folded)
    /// It doesn't multiply with eq_3b yet.
    pub cur_sum: [T; D_EF],
    pub beta: [T; D_EF],
    pub eq_3b: [T; D_EF],

    /// The summed num and denom for all interactions.
    /// It's summed over all the interactions in the AIR: cur_sum * eq_3b when is_first_in_message
    pub final_acc_num: [T; D_EF],
    pub final_acc_denom: [T; D_EF],
}

self.transcript_bus.sample_ext(
    builder,
    local.proof_idx,
    local.beta_tidx,
    local.beta,
    local.is_valid * local.is_first,
);

self.air_shape_bus.lookup_key(
    builder,
    local.proof_idx,
    AirShapeBusMessage {
        sort_idx: local.sort_idx.into(),
        property_idx: AirShapeProperty::NumInteractions.to_field(),
        value: (local.interaction_idx + AB::Expr::ONE) * local.has_interactions,
    },
    next_is_first_in_air_or_invalid * local.is_valid,
);
self.air_shape_bus.lookup_key(
    builder,
    local.proof_idx,
    AirShapeBusMessage {
        sort_idx: local.sort_idx.into(),
        property_idx: AirShapeProperty::AirId.to_field(),
        value: local.air_idx.into(),
    },
    local.is_first_in_air,
);
self.interactions_folding_input_bus.receive(
    builder,
    local.proof_idx,
    InteractionsFoldingInputMessage {
        tidx: local.beta_tidx,
    },
    local.is_first,
);

// ======================== beta and cur sum consistency ============================
assert_array_eq(&mut builder.when(is_same_proof), local.beta, next.beta);
assert_array_eq(
    &mut builder.when(is_same_message * not(local.is_first_in_message)),
    local.cur_sum,
    ext_field_add(
        local.value,
        ext_field_multiply::<AB::Expr>(local.beta, next.cur_sum),
    ),
);
// numerator and the last element of the message are just the corresponding values
assert_array_eq(
    &mut builder.when(next_is_first_in_message_or_invalid + local.is_first_in_message),
    local.cur_sum,
    local.value,
);

// final_acc_num only changes when it's first in message
assert_array_eq(
    &mut builder
        .when(not(local.is_first_in_message) * local.is_valid * is_same_air.clone()),
    local.final_acc_num,
    next.final_acc_num,
);
assert_array_eq(
    &mut builder.when(local.is_first_in_message * local.has_interactions),
    local.final_acc_num,
    ext_field_add(
        next.final_acc_num,
        ext_field_multiply(local.cur_sum, local.eq_3b),
    ),
);
assert_zeros(
    &mut builder
        .when(local.is_first_in_message * (local.is_valid - local.has_interactions)),
    local.final_acc_num,
);
assert_zeros(
    &mut builder
        .when(local.is_first_in_message * (local.is_valid - local.has_interactions)),
    local.final_acc_denom,
);
// final_acc_denom only changes when it's second in message
assert_array_eq(
    &mut builder.when(
        (not(local.is_second_in_message) + not(local.has_interactions))
            * local.is_valid
            * is_same_air.clone(),
    ),
    local.final_acc_denom,
    next.final_acc_denom,
);
assert_array_eq(
    &mut builder.when(local.is_second_in_message * local.is_valid),
    local.final_acc_denom,
    ext_field_add(
        next.final_acc_denom,
        ext_field_multiply(local.cur_sum, local.eq_3b),
    ),
);

self.expression_claim_bus.send(
    builder,
    local.proof_idx,
    ExpressionClaimMessage {
        is_interaction: AB::Expr::ONE,
        idx: local.sort_idx * AB::Expr::TWO,
        // value: ext_field_multiply(local.cur_sum, local.eq_3b),
        value: local.final_acc_num.map(Into::into),
    },
    local.is_first_in_air * local.is_valid,
);
self.expression_claim_bus.send(
    builder,
    local.proof_idx,
    ExpressionClaimMessage {
        is_interaction: AB::Expr::ONE,
        idx: local.sort_idx * AB::Expr::TWO + AB::Expr::ONE,
        // value: ext_field_multiply(next.cur_sum, next.eq_3b),
        value: local.final_acc_denom.map(Into::into),
    },
    local.is_first_in_air * local.is_valid,
);

self.interaction_bus.receive(
    builder,
    local.proof_idx,
    InteractionsFoldingMessage {
        air_idx: local.air_idx.into(),
        interaction_idx: local.interaction_idx.into(),
        is_mult: AB::Expr::ZERO,
        idx_in_message: local.idx_in_message.into(),
        value: local.value.map(Into::into),
    },
    local.has_interactions
        * (AB::Expr::ONE - local.is_first_in_message - local.is_bus_index),
);
self.interaction_bus.receive(
    builder,
    local.proof_idx,
    InteractionsFoldingMessage {
        air_idx: local.air_idx.into(),
        interaction_idx: local.interaction_idx.into(),
        is_mult: AB::Expr::ONE,
        idx_in_message: AB::Expr::ZERO,
        value: local.value.map(Into::into),
    },
    local.is_first_in_message * local.has_interactions,
);
self.interaction_bus.receive(
    builder,
    local.proof_idx,
    InteractionsFoldingMessage {
        air_idx: local.air_idx.into(),
        interaction_idx: local.interaction_idx.into(),
        is_mult: AB::Expr::ZERO,
        idx_in_message: AB::Expr::NEG_ONE,
        value: local.value.map(Into::into),
    },
    local.is_bus_index,
);

self.eq_3b_bus.receive(
    builder,
    local.proof_idx,
    Eq3bMessage {
        sort_idx: local.sort_idx,
        interaction_idx: local.interaction_idx,
        eq_3b: local.eq_3b,
    },
    local.has_interactions * local.is_first_in_message,
);

self.constraints_folding_input_bus.receive(
    builder,
    local.proof_idx,
    ConstraintsFoldingInputMessage {
        tidx: local.lambda_tidx,
    },
    local.is_first,
);
self.transcript_bus.sample_ext(
    builder,
    local.proof_idx,
    local.lambda_tidx,
    local.lambda,
    local.is_valid * local.is_first,
);

// ======================== lambda and cur sum consistency ============================
assert_array_eq(&mut builder.when(is_same_proof), local.lambda, next.lambda);
assert_array_eq(
    &mut builder.when(is_same_air.clone()),
    local.cur_sum,
    ext_field_add(
        local.value,
        ext_field_multiply::<AB::Expr>(local.lambda, next.cur_sum),
    ),
);
assert_array_eq(
    &mut builder.when(is_same_air.clone()),
    local.eq_n,
    next.eq_n,
);
// numerator and the last element of the message are just the corresponding values
assert_array_eq(
    &mut builder.when(AB::Expr::ONE - is_same_air.clone()),
    local.cur_sum,
    local.value,
);
// If we don't have constraints then `value` is zero
assert_zeros(
    &mut builder
        .when(local.is_first_in_air)
        .when(not::<AB::Expr>(is_same_air.clone())),
    local.value,
);

self.n_lift_bus.receive(
    builder,
    local.proof_idx,
    NLiftMessage {
        air_idx: local.air_idx,
        n_lift: local.n_lift,
    },
    local.is_first_in_air * local.is_valid,
);
self.constraint_bus.receive(
    builder,
    local.proof_idx,
    ConstraintsFoldingMessage {
        air_idx: local.air_idx.into(),
        constraint_idx: local.constraint_idx - AB::Expr::ONE,
        value: local.value.map(Into::into),
    },
    local.is_valid * (AB::Expr::ONE - local.is_first_in_air),
);
let folded_sum: [AB::Expr; D_EF] = ext_field_add(
    ext_field_multiply_scalar::<AB::Expr>(next.cur_sum, is_same_air.clone()),
    ext_field_multiply_scalar::<AB::Expr>(local.cur_sum, AB::Expr::ONE - is_same_air),
);
self.expression_claim_bus.send(
    builder,
    local.proof_idx,
    ExpressionClaimMessage {
        is_interaction: AB::Expr::ZERO,
        idx: local.sort_idx.into(),
        value: ext_field_multiply(folded_sum, local.eq_n),
    },
    local.is_first_in_air * local.is_valid,
);

self.eq_n_outer_bus.lookup_key(
    builder,
    local.proof_idx,
    EqNOuterMessage {
        is_sharp: AB::Expr::ZERO,
        n: local.n_lift.into(),
        value: local.eq_n.map(Into::into),
    },
    local.is_first_in_air * local.is_valid,
);

// Coeff index starts at univariate degree
builder
    .when(local.is_first)
    .assert_eq(local.coeff_idx, AB::Expr::from_usize(self.univariate_deg));
// Coeff index decrements by 1
builder
    .when(is_transition.clone())
    .assert_eq(next.coeff_idx, local.coeff_idx - AB::Expr::ONE);
// Coeff index ends at zero
builder.when(is_last.clone()).assert_zero(local.coeff_idx);

let domain_size = AB::Expr::from_usize(1 << self.l_skip);

// Initialize sum over roots
assert_array_eq(
    &mut builder
        .when(local.is_first)
        .when(local.is_omega_skip_power_equal_to_one),
    local.sum_at_roots,
    ext_field_multiply_scalar(local.coeff, domain_size.clone()),
);
assert_zeros(
    &mut builder
        .when(local.is_first)
        .when(not(local.is_omega_skip_power_equal_to_one)),
    local.sum_at_roots,
);
// Add c * 2^{l_skip} at every 2^{l_skip} coefficient
assert_array_eq(
    &mut builder
        .when(is_transition.clone())
        .when(next.is_omega_skip_power_equal_to_one),
    next.sum_at_roots,
    ext_field_add(
        local.sum_at_roots,
        ext_field_multiply_scalar(next.coeff, domain_size.clone()),
    ),
);
// Keep the sum over roots unchanged for other values
assert_array_eq(
    &mut builder
        .when(is_transition.clone())
        .when(not(next.is_omega_skip_power_equal_to_one)),
    next.sum_at_roots,
    local.sum_at_roots,
);

assert_array_eq(&mut builder.when(is_transition.clone()), next.r, local.r);

// Initialize evaluation
// e = c
assert_array_eq(
    &mut builder.when(local.is_first),
    local.value_at_r,
    local.coeff,
);
// e' = c + r * e
assert_array_eq(
    &mut builder.when(is_transition.clone()),
    next.value_at_r,
    ext_field_add(next.coeff, ext_field_multiply(next.r, local.value_at_r)),
);

// Sample r
self.transcript_bus.sample_ext(
    builder,
    local.proof_idx,
    local.tidx + AB::Expr::from_usize(D_EF),
    local.r,
    local.is_first,
);
// Observe coefficients
self.transcript_bus.observe_ext(
    builder,
    local.proof_idx,
    local.tidx,
    local.coeff,
    local.is_valid,
);

// Receive initial tidx value
self.univariate_sumcheck_input_bus.receive(
    builder,
    local.proof_idx,
    UnivariateSumcheckInputMessage { tidx: local.tidx },
    is_last.clone(),
);
// Send tidx when there are no multilinear rounds
self.stacking_module_bus.send(
    builder,
    local.proof_idx,
    StackingModuleMessage {
        // Skip r
        tidx: local.tidx + AB::Expr::from_usize(2 * D_EF),
    },
    local.is_first,
);

self.claim_bus.receive(
    builder,
    local.proof_idx,
    SumcheckClaimMessage {
        round: AB::Expr::NEG_ONE,
        value: local.sum_at_roots.map(Into::into),
    },
    is_last.clone(),
);
self.claim_bus.send(
    builder,
    local.proof_idx,
    SumcheckClaimMessage {
        round: AB::Expr::ZERO,
        value: local.value_at_r.map(Into::into),
    },
    is_last,
);

self.randomness_bus.send(
    builder,
    local.proof_idx,
    ConstraintSumcheckRandomness {
        idx: AB::Expr::ZERO,
        challenge: local.r.map(Into::into),
    },
    local.is_first,
);

// Here idx = 0 and is called once per proof_idx
self.batch_constraint_conductor_bus.add_key_with_lookups(
    builder,
    local.proof_idx,
    BatchConstraintConductorMessage {
        msg_type: BatchConstraintInnerMessageType::R.to_field(),
        idx: AB::Expr::ZERO,
        value: local.r.map(Into::into),
    },
    local.is_valid * local.is_first * AB::Expr::TWO,
);

let d_factorial_inv = AB::Expr::from_prime_subfield(
    <AB::Expr as PrimeCharacteristicRing>::PrimeSubfield::from_usize((1..=s_deg).product())
        .inverse(),
);
// Starts at d!
builder
    .when(local.is_first_eval)
    .assert_eq(local.denom_inv, d_factorial_inv);
// 1 / (i + 1)!(d - i - 1)!  (i + 1) = 1 / i!(d - i)! * (d - i)
builder.when(is_transition_eval.clone()).assert_eq(
    next.denom_inv * next.eval_idx,
    local.denom_inv * (AB::Expr::from_usize(s_deg) - local.eval_idx),
);

///////////////////////////////////////////////////////////////////////
// Prefix/Suffix Product Constraints
///////////////////////////////////////////////////////////////////////

assert_array_eq(
    &mut builder.when(is_transition_eval.clone()),
    next.r,
    local.r,
);

// Prefix Product
// Starts at 1
assert_one_ext(&mut builder.when(local.is_first_eval), local.prefix_product);
// p' = p * (r - i)
assert_array_eq(
    &mut builder.when(is_transition_eval.clone()),
    next.prefix_product,
    ext_field_multiply(
        local.prefix_product,
        ext_field_subtract_scalar(local.r, local.eval_idx),
    ),
);

// Suffix Product
// Ends at 1
assert_one_ext(
    &mut builder.when(is_last_eval.clone()),
    local.suffix_product,
);
// s = s' * (i + 1 - r)
assert_array_eq(
    &mut builder.when(is_transition_eval.clone()),
    local.suffix_product,
    ext_field_multiply(
        next.suffix_product,
        scalar_subtract_ext_field(local.eval_idx + AB::Expr::ONE, local.r),
    ),
);

// Lagrange coefficient
assert_array_eq(
    &mut builder.when(local.is_valid),
    local.lagrange_coeff,
    ext_field_multiply_scalar(
        ext_field_multiply(local.prefix_product, local.suffix_product),
        local.denom_inv,
    ),
);

// Initialize at first evaluation
assert_array_eq(
    &mut builder.when(local.is_first_eval),
    local.cur_sum,
    ext_field_multiply(local.eval, local.lagrange_coeff),
);

// Cumulative sum
assert_array_eq(
    &mut builder.when(is_transition_eval.clone()),
    next.cur_sum,
    ext_field_add(
        local.cur_sum,
        ext_field_multiply(next.eval, next.lagrange_coeff),
    ),
);

// Observe evaluations s(1), s(2) etc.
self.transcript_bus.observe_ext(
    builder,
    local.proof_idx,
    local.tidx,
    next.eval,
    is_transition_eval.clone() * is_not_dummy.clone(),
);
// Sample challenge r
self.transcript_bus.sample_ext(
    builder,
    local.proof_idx,
    local.tidx,
    local.r,
    is_last_eval.clone() * is_not_dummy.clone(),
);

// Receive tidx from univariate sumcheck and send it to stacking module
self.stacking_module_bus.receive(
    builder,
    local.proof_idx,
    StackingModuleMessage { tidx: local.tidx },
    local.is_proof_start * is_not_dummy.clone(),
);
self.stacking_module_bus.send(
    builder,
    local.proof_idx,
    StackingModuleMessage {
        tidx: local.tidx + AB::Expr::from_usize(D_EF),
    },
    is_proof_end.clone() * is_not_dummy.clone(),
);

self.claim_bus.receive(
    builder,
    local.proof_idx,
    SumcheckClaimMessage {
        round: local.round_idx.into(),
        value: ext_field_add(local.eval, next.eval),
    },
    local.is_first_eval * is_not_dummy.clone(),
);
self.claim_bus.send(
    builder,
    local.proof_idx,
    SumcheckClaimMessage {
        round: local.round_idx + AB::Expr::ONE,
        value: local.cur_sum.map(Into::into),
    },
    is_last_eval.clone() * is_not_dummy.clone(),
);

self.randomness_bus.send(
    builder,
    local.proof_idx,
    ConstraintSumcheckRandomness {
        idx: local.round_idx + AB::Expr::ONE,
        challenge: local.r.map(|x| x.into()),
    },
    local.is_first_eval * is_not_dummy.clone(),
);
// Here idx > 0 and all idx are distinct within one proof_idx
self.batch_constraint_conductor_bus.add_key_with_lookups(
    builder,
    local.proof_idx,
    BatchConstraintConductorMessage {
        msg_type: BatchConstraintInnerMessageType::R.to_field(),
        idx: local.round_idx + AB::Expr::ONE,
        value: local.r.map(|x| x.into()),
    },
    local.is_first_eval * is_not_dummy,
);

// Within transition, idx increases by nth_bit * hypercube_volume
builder
    .when(within_one_interaction.clone())
    .assert_eq(next.idx, local.idx + local.nth_bit * local.hypercube_volume);
// It can't increase if n < n_lift
builder
    .when(not(local.n_at_least_n_lift))
    .assert_zero(local.nth_bit);
// When transition, eq multiplies correspondingly
assert_array_eq(
    &mut builder.when(within_one_interaction.clone()),
    next.eq,
    ext_field_multiply(
        local.eq,
        ext_field_add::<AB::Expr>(
            ext_field_multiply_scalar(local.xi, local.nth_bit),
            ext_field_multiply_scalar::<AB::Expr>(
                ext_field_one_minus(local.xi),
                AB::Expr::ONE - local.nth_bit,
            ),
        ),
    ),
);

self.batch_constraint_conductor_bus.lookup_key(
    builder,
    local.proof_idx,
    BatchConstraintConductorMessage {
        msg_type: BatchConstraintInnerMessageType::Xi.to_field(),
        idx: local.n + AB::Expr::from_usize(self.l_skip),
        value: local.xi.map(|x| x.into()),
    },
    local.n_at_least_n_lift * within_one_interaction,
);

self.eq_3b_shape_bus.lookup_key(
    builder,
    local.proof_idx,
    Eq3bShapeMessage {
        sort_idx: local.sort_idx.into(),
        n_lift: local.n_lift.into(),
        n_logup: local.n_logup.into(),
        num_interactions: local.interaction_idx + not(local.has_no_interactions),
    },
    LoopSubAir::local_is_last(local.is_valid, next.is_valid, next.is_first_in_air),
);

self.eq_3b_bus.send(
    builder,
    local.proof_idx,
    Eq3bMessage {
        sort_idx: local.sort_idx,
        interaction_idx: local.interaction_idx,
        eq_3b: local.eq,
    },
    is_last_in_interaction * (local.is_valid - local.has_no_interactions),
);

// ========================= eq consistency ===============================
let mult = ext_field_one_minus::<AB::Expr>(ext_field_subtract::<AB::Expr>(
    ext_field_add(local.xi_n, local.r_n),
    ext_field_multiply_scalar::<AB::Expr>(
        ext_field_multiply(local.xi_n, local.r_n),
        AB::Expr::TWO,
    ),
));
builder.assert_eq(
    local.is_transition_and_n_less_than_n_max,
    is_transition.clone() * local.n_less_than_n_max,
);
assert_array_eq(
    &mut builder.when(local.is_transition_and_n_less_than_n_max),
    next.eq,
    ext_field_multiply(local.eq, mult.clone()),
);
assert_array_eq(
    &mut builder.when(local.is_transition_and_n_less_than_n_max),
    next.eq_sharp,
    ext_field_multiply(local.eq_sharp, mult.clone()),
);

self.eq_n_outer_bus.add_key_with_lookups(
    builder,
    next.proof_idx,
    EqNOuterMessage {
        is_sharp: AB::Expr::ZERO,
        n: next.n.into(),
        value: ext_field_multiply(next.eq, next.r_product),
    },
    next.is_valid * next.num_traces,
);
self.eq_n_outer_bus.add_key_with_lookups(
    builder,
    next.proof_idx,
    EqNOuterMessage {
        is_sharp: AB::Expr::ONE,
        n: next.n.into(),
        value: ext_field_multiply(next.eq_sharp, next.r_product),
    },
    next.is_valid * next.num_traces * AB::Expr::TWO, // two because num+denom per trace
);

self.zero_n_bus.receive(
    builder,
    local.proof_idx,
    EqZeroNMessage {
        is_sharp: AB::Expr::ZERO,
        value: local.eq.map(|x| x.into()),
    },
    local.is_first,
);
self.zero_n_bus.receive(
    builder,
    local.proof_idx,
    EqZeroNMessage {
        is_sharp: AB::Expr::ONE,
        value: local.eq_sharp.map(|x| x.into()),
    },
    local.is_first,
);

// ======================== Values recalculation ==========================
assert_one_ext(&mut builder.when(local.is_first), local.res);

let mut when_transition = builder.when(is_transition);
assert_array_eq(
    &mut when_transition,
    next.x.map(Into::into),
    ext_field_multiply::<AB::Expr>(local.x, local.x),
);
assert_array_eq(
    &mut when_transition,
    next.y.map(Into::into),
    ext_field_multiply::<AB::Expr>(local.y, local.y),
);

let x_plus_y = ext_field_add::<AB::Expr>(local.x, local.y);
let one_minus_x = ext_field_one_minus::<AB::Expr>(local.x);
let one_minus_y = ext_field_one_minus::<AB::Expr>(local.y);
let next_res_expected = ext_field_add::<AB::Expr>(
    ext_field_multiply::<AB::Expr>(x_plus_y, local.res),
    ext_field_multiply::<AB::Expr>(one_minus_x, one_minus_y),
);
assert_array_eq(
    &mut when_transition,
    next.res.map(Into::into),
    next_res_expected,
);

// =========================== Root consistency =============================
// If iter_idx doesn't become zero (increases by one), then:
// - root_pow is multiplied by root,
// - root is preserved.
builder
    .when(next.iter_idx)
    .assert_eq(next.root_pow, local.root_pow * local.root);
builder.when(next.iter_idx).assert_eq(local.root, next.root);
builder
    .when(next.iter_idx)
    .assert_eq(local.root_half_order, next.root_half_order);
// Otherwise the new root is the square of the current one, and the root order doubles.
builder
    .when(next.is_first_iter * not(next.is_first))
    .assert_eq(local.root_half_order * AB::Expr::TWO, next.root_half_order);
builder
    .when(next.is_first_iter * not(next.is_first))
    .assert_eq(local.root, next.root * next.root);
// Important: we need to enforce dropping iter_idx to zero if root_pow is going to become
// one. We can leave this to inner interactions, but then we need to guarantee that
// the first layer has size 1.
builder
    .when(next.is_valid * local.is_first)
    .assert_one(next.is_first_iter);
// Also, on the first row we have some conditions
builder
    .when(local.is_valid * local.is_first)
    .assert_eq(local.root, AB::Expr::NEG_ONE);
builder
    .when(local.is_valid * local.is_first)
    .assert_eq(local.root_half_order, AB::Expr::ONE);

self.eq_bus.receive(
    builder,
    local.proof_idx,
    EqSharpUniMessage {
        xi_idx: local.xi_idx + AB::Expr::ONE,
        iter_idx: local.iter_idx.into(),
        product: local.product_before.map(|x| x.into()),
    },
    local.is_valid * (AB::Expr::ONE - local.is_first),
);
let second: [AB::Expr; D_EF] = ext_field_multiply_scalar(local.xi, local.root_pow);
let one_minus_xi: [AB::Expr; D_EF] = ext_field_one_minus(local.xi);

self.eq_bus.send(
    builder,
    local.proof_idx,
    EqSharpUniMessage {
        xi_idx: local.xi_idx.into(),
        iter_idx: local.iter_idx.into(),
        product: ext_field_multiply(
            local.product_before,
            ext_field_add::<AB::Expr>(one_minus_xi.clone(), second.clone()),
        ),
    },
    local.is_valid,
);
self.eq_bus.send(
    builder,
    local.proof_idx,
    EqSharpUniMessage {
        xi_idx: local.xi_idx.into(),
        iter_idx: local.iter_idx + local.root_half_order,
        product: ext_field_multiply(
            local.product_before,
            ext_field_subtract::<AB::Expr>(one_minus_xi.clone(), second.clone()),
        ),
    },
    local.is_valid,
);

assert_array_eq(&mut builder.when(is_same_proof.clone()), next.r, local.r);
assert_array_eq(
    &mut builder.when(LoopSubAir::local_is_last(
        local.is_valid,
        next.is_valid,
        next.is_first,
    )),
    local.cur_sum,
    local.coeff,
);
assert_array_eq(
    &mut builder.when(is_same_proof),
    local.cur_sum,
    ext_field_add(local.coeff, ext_field_multiply(local.r, next.cur_sum)),
);

self.r_bus.lookup_key(
    builder,
    local.proof_idx,
    BatchConstraintConductorMessage {
        msg_type: BatchConstraintInnerMessageType::R.to_field(),
        idx: AB::Expr::ZERO,
        value: local.r.map(|x| x.into()),
    },
    local.is_valid * local.is_first,
);
self.eq_bus.receive(
    builder,
    local.proof_idx,
    EqSharpUniMessage {
        xi_idx: AB::Expr::ZERO,
        iter_idx: local.idx.into(),
        product: local.coeff.map(|x| x.into()),
    },
    local.is_valid,
);
let l_skip_inv: AB::Expr = AB::F::from_usize(1 << self.l_skip).inverse().into();
self.zero_n_bus.send(
    builder,
    local.proof_idx,
    EqZeroNMessage {
        is_sharp: AB::Expr::ONE,
        value: local.cur_sum.map(|x| l_skip_inv.clone() * x),
    },
    local.is_valid * local.is_first,
);

assert_array_eq(
    &mut builder.when(local.is_valid - local.is_last_hypercube),
    ext_field_multiply(local.u_pow, local.u_pow),
    next.u_pow,
);

assert_array_eq(
    &mut builder.when(local.is_valid - local.is_last_hypercube),
    ext_field_multiply(local.r_pow, local.r_pow),
    next.r_pow,
);

assert_array_eq(
    &mut builder.when(local.is_valid - local.is_last_hypercube),
    ext_field_multiply(local.prod_u_r, ext_field_add(next.u_pow, next.r_pow)),
    next.prod_u_r,
);

assert_array_eq(
    &mut builder.when(local.is_valid - local.is_last_hypercube),
    ext_field_multiply(
        local.prod_1_r,
        ext_field_add(next.r_pow, base_to_ext::<AB::Expr>(AB::F::ONE)),
    ),
    next.prod_1_r,
);

let eq = ext_field_add_scalar::<AB::Expr>(
    ext_field_subtract(local.prod_u_r, next.u_pow),
    AB::F::ONE,
);
let k_rot = ext_field_add_scalar::<AB::Expr>(
    ext_field_subtract(local.prod_u_r_omega, next.u_pow),
    AB::F::ONE,
);

let is_neg = local.neg_hypercube * local.neg_hypercube_nz_inv;
builder.when(local.neg_hypercube).assert_one(is_neg.clone());
self.result_bus.send(
    builder,
    local.proof_idx,
    EqNegResultMessage {
        n: AB::Expr::ZERO - local.neg_hypercube,
        eq,
        k_rot,
    },
    is_neg * next.is_last_hypercube,
);

#[derive(Debug, Clone, Copy, EnumIter, EnumCount)]
pub(crate) enum NodeKind {
    // Args: (col_idx, is_next)
    VarPreprocessed = 0,
    // Args: (col_idx, is_next)
    VarMain = 1,
    // Args: (pv_idx,)
    VarPublicValue = 2,
    // Args: ()
    SelIsFirst = 3,
    // Args: ()
    SelIsLast = 4,
    // Args: ()
    SelIsTransition = 5,
    // Args: (val,)
    Constant = 6,
    // Args: (left_node_idx, right_node_idx)
    Add = 7,
    // Args: (left_node_idx, right_node_idx)
    Sub = 8,
    // Args: (node_idx,)
    Neg = 9,
    // Args: (left_node_idx, right_node_idx)
    Mul = 10,
    // Args: (node_idx,)
    InteractionMult = 11,
    // Args: (node_idx, idx_in_message)
    InteractionMsgComp = 12,
    // Args: (node_idx,)
    InteractionBusIndex = 13,
}

#[derive(AlignedBorrow, Copy, Clone)]
#[repr(C)]
pub struct CachedSymbolicExpressionColumns<T> {
    pub(in crate::batch_constraint) flags: [T; NUM_FLAGS],

    pub(in crate::batch_constraint) air_idx: T,
    pub(in crate::batch_constraint) node_or_interaction_idx: T,
    /// Attributes that define this gate. For binary gates such as Add, Mul, etc.,
    /// this contains the node_idx's. For InteractionMsgComp, it gives (node_idx, idx_in_message).
    /// See [[NodeKind]].
    pub(in crate::batch_constraint) attrs: [T; 3],
    pub(in crate::batch_constraint) fanout: T,

    pub(in crate::batch_constraint) is_constraint: T,
    pub(in crate::batch_constraint) constraint_idx: T,
}

#[derive(AlignedBorrow, Copy, Clone)]
#[repr(C)]
pub struct SingleMainSymbolicExpressionColumns<T> {
    // 0 = proof absent from this slot, 1 = proof present with absent air, 2 = proof present with
    // present air
    pub(in crate::batch_constraint) slot_state: T,
    // Dynamic arguments. For Add/Mul/Sub, this splits into two extension-field elements.
    // For selectors:
    //   args[0..D_EF)   = sel_uni witness (base or rotated depending on selector type).
    //   args[D_EF..2*D_EF) = eq-prefix witness (prod r_i or prod (1-r_i)).
    pub(in crate::batch_constraint) args: [T; 2 * D_EF],
    pub(in crate::batch_constraint) sort_idx: T,
    pub(in crate::batch_constraint) n_abs: T,
    pub(in crate::batch_constraint) is_n_neg: T,
}

let mut value = [AB::Expr::ZERO; D_EF];
for node_kind in NodeKind::iter() {
    // deg 2
    let sel = enc.get_flag_expr::<AB>(node_kind as usize, &flags);
    let expr = match node_kind {
        NodeKind::Add => ext_field_add::<AB::Expr>(arg_ef0, arg_ef1),
        NodeKind::Sub => ext_field_subtract::<AB::Expr>(arg_ef0, arg_ef1),
        NodeKind::Neg => scalar_subtract_ext_field::<AB::Expr>(AB::F::ZERO, arg_ef0),
        NodeKind::Mul => ext_field_multiply::<AB::Expr>(arg_ef0, arg_ef1),
        NodeKind::Constant => base_to_ext(cached_cols.attrs[0]),
        NodeKind::VarPublicValue => base_to_ext(cols.args[0]),
        NodeKind::SelIsFirst => ext_field_multiply(arg_ef0, arg_ef1),
        NodeKind::SelIsLast => ext_field_multiply(arg_ef0, arg_ef1),
        NodeKind::SelIsTransition => scalar_subtract_ext_field(
            AB::Expr::ONE,
            ext_field_multiply(arg_ef0, arg_ef1),
        ),
        NodeKind::VarPreprocessed
        | NodeKind::VarMain
        | NodeKind::InteractionMult
        | NodeKind::InteractionMsgComp => arg_ef0.map(Into::into),
        NodeKind::InteractionBusIndex => {
            base_to_ext(cached_cols.attrs[0] + AB::Expr::ONE)
        }
    };
    // deg <= 4
    value = ext_field_add::<AB::Expr>(
        value,
        ext_field_multiply_scalar::<AB::Expr>(expr, sel),
    );
}

self.expr_bus.add_key_with_lookups(
    builder,
    proof_idx,
    SymbolicExpressionMessage {
        air_idx: cached_cols.air_idx.into(),
        node_idx: cached_cols.node_or_interaction_idx.into(),
        value: value.clone(),
    },
    air_present.clone() * cached_cols.fanout,
);
self.expr_bus.lookup_key(
    builder,
    proof_idx,
    SymbolicExpressionMessage {
        air_idx: cached_cols.air_idx,
        node_idx: cached_cols.attrs[0],
        value: arg_ef0,
    },
    air_present.clone() * is_arg0_node_idx.clone(),
);
self.expr_bus.lookup_key(
    builder,
    proof_idx,
    SymbolicExpressionMessage {
        air_idx: cached_cols.air_idx,
        node_idx: cached_cols.attrs[1],
        value: arg_ef1,
    },
    air_present.clone() * is_arg1_node_idx.clone(),
);

let is_var = enc.contains_flag::<AB>(
    &flags,
    &[NodeKind::VarMain, NodeKind::VarPreprocessed].map(|x| x as usize),
);
self.column_claims_bus.receive(
    builder,
    proof_idx,
    ColumnClaimsMessage {
        sort_idx: cols.sort_idx.into(),
        part_idx: cached_cols.attrs[1].into(),
        col_idx: cached_cols.attrs[0].into(),
        claim: array::from_fn(|i| cols.args[i].into()),
        is_rot: cached_cols.attrs[2].into(),
    },
    is_var * air_present.clone(),
);
self.public_values_bus.receive(
    builder,
    proof_idx,
    PublicValuesBusMessage {
        air_idx: cached_cols.air_idx,
        pv_idx: cached_cols.attrs[0],
        value: cols.args[0],
    },
    enc.get_flag_expr::<AB>(NodeKind::VarPublicValue as usize, &flags)
        * air_present.clone(),
);

self.interactions_folding_bus.send(
    builder,
    proof_idx,
    InteractionsFoldingMessage {
        air_idx: cached_cols.air_idx.into(),
        interaction_idx: cached_cols.node_or_interaction_idx.into(),
        is_mult,
        idx_in_message: cached_cols.attrs[1].into(),
        value: value.clone(),
    },
    is_interaction * air_present.clone(),
);
self.interactions_folding_bus.send(
    builder,
    proof_idx,
    InteractionsFoldingMessage {
        air_idx: cached_cols.air_idx.into(),
        interaction_idx: cached_cols.node_or_interaction_idx.into(),
        is_mult: AB::Expr::ZERO,
        idx_in_message: AB::Expr::NEG_ONE,
        value: value.clone(),
    },
    is_bus_index * air_present.clone(),
);
self.constraints_folding_bus.send(
    builder,
    proof_idx,
    ConstraintsFoldingMessage {
        air_idx: cached_cols.air_idx.into(),
        constraint_idx: cached_cols.constraint_idx.into(),
        value: value.clone(),
    },
    cached_cols.is_constraint * air_present,
);

#[derive(AlignedBorrow, Copy, Clone, Debug)]
#[repr(C)]
pub struct ExpressionClaimCols<T> {
    // --- Loop structure (enforced by NestedForLoopSubAir<4>) ---
    pub is_valid: T,
    /// First row of a proof. Marks proof boundaries.
    pub is_first: T,
    pub proof_idx: T,
    /// 0 = interaction group, 1 = constraint group. Monotone within a proof.
    pub group_idx: T,
    /// Marks the first row of each group (set at proof start and interaction→constraint boundary).
    pub is_first_in_group: T,

    // --- Claim indexing (derived from loop counters) ---
    /// Claim index within its group. For interactions: `2 * trace_idx + idx_parity` (0..2t).
    /// For constraints: `trace_idx` (0..t).
    pub idx: T,
    /// 0 = numerator, 1 = denominator. Always 0 on constraint rows. Alternates on interaction
    /// rows.
    pub idx_parity: T,
    /// Sorted trace index within the group. Monotone non-decreasing; resets at group boundaries.
    pub trace_idx: T,
    /// The received evaluation claim. Note that for interactions, this is without norm_factor and
    /// eq_sharp_ns. These are interactions_evals (without norm_factor and eq_sharp_ns) and
    /// constraint_evals in the rust verifier.
    pub value: [T; D_EF],
    /// Receive from eq_ns AIR
    pub eq_sharp_ns: [T; D_EF],

    /// For folding with mu.
    pub cur_sum: [T; D_EF],
    pub mu: [T; D_EF],
    pub multiplier: [T; D_EF],

    /// Need to know n as if n<0, we need to multiply some norm_factor.
    pub n_abs: T,
    pub n_abs_pow: T,
    pub n_sign: T,
    /// The round idx for final sumcheck claim.
    pub num_multilinear_sumcheck_rounds: T,
}

// multiplier = 1 if not interaction
assert_array_eq(
    &mut builder.when(local.group_idx).when(local.is_valid),
    local.multiplier,
    base_to_ext::<AB::Expr>(AB::Expr::ONE),
);

// IF negative n and numerator
assert_array_eq(
    &mut builder.when(local.n_sign * (is_interaction.clone() - local.idx_parity)),
    ext_field_multiply_scalar::<AB::Expr>(local.multiplier, local.n_abs_pow),
    local.eq_sharp_ns,
);
// ELSE 1: positive n, interaction row
assert_array_eq(
    &mut builder.when(is_interaction.clone() * (AB::Expr::ONE - local.n_sign)),
    local.multiplier,
    local.eq_sharp_ns,
);
// ELSE 2: denominator row
assert_array_eq(
    &mut builder.when(local.idx_parity),
    local.multiplier,
    local.eq_sharp_ns,
);

// === cum sum folding ===
// Fold recurrence within a proof: cur_sum = value * multiplier + next_cur_sum * mu
assert_array_eq(
    &mut builder.when(is_same_proof),
    local.cur_sum,
    ext_field_add::<AB::Expr>(
        ext_field_multiply::<AB::Expr>(local.value, local.multiplier),
        ext_field_multiply::<AB::Expr>(next.cur_sum, local.mu),
    ),
);
// Terminal base case: last row of each proof's fold
assert_array_eq(
    &mut builder.when(is_last_in_proof),
    local.cur_sum,
    ext_field_multiply::<AB::Expr>(local.value, local.multiplier),
);

self.expr_claim_bus.receive(
    builder,
    local.proof_idx,
    ExpressionClaimMessage {
        is_interaction: is_interaction.clone(),
        idx: local.idx.into(),
        value: local.value.map(Into::into),
    },
    local.is_valid,
);

self.mu_bus.lookup_key(
    builder,
    local.proof_idx,
    BatchConstraintConductorMessage {
        msg_type: BatchConstraintInnerMessageType::Mu.to_field(),
        idx: AB::Expr::ZERO,
        value: local.mu.map(Into::into),
    },
    local.is_first * local.is_valid,
);

// Receive n_max value from proof shape air
self.expression_claim_n_max_bus.receive(
    builder,
    local.proof_idx,
    ExpressionClaimNMaxMessage {
        n_max: local.num_multilinear_sumcheck_rounds,
    },
    local.is_first * local.is_valid,
);

self.sumcheck_claim_bus.receive(
    builder,
    local.proof_idx,
    SumcheckClaimMessage::<AB::Expr> {
        round: local.num_multilinear_sumcheck_rounds.into(),
        value: local.cur_sum.map(Into::into),
    },
    local.is_first * local.is_valid,
);

self.hyperdim_bus.lookup_key(
    builder,
    local.proof_idx,
    HyperdimBusMessage {
        sort_idx: local.trace_idx.into(),
        n_abs: local.n_abs.into(),
        n_sign_bit: local.n_sign.into(),
    },
    local.is_valid * (is_interaction.clone() - local.idx_parity),
);

self.eq_n_outer_bus.lookup_key(
    builder,
    local.proof_idx,
    EqNOuterMessage {
        is_sharp: AB::Expr::ONE,
        n: local.n_abs * (AB::Expr::ONE - local.n_sign),
        value: local.eq_sharp_ns.map(Into::into),
    },
    local.is_valid * is_interaction.clone(),
);

self.pow_checker_bus.lookup_key(
    builder,
    PowerCheckerBusMessage {
        log: local.n_abs.into(),
        exp: local.n_abs_pow.into(),
    },
    local.is_valid * is_interaction,
);
